var b="url",c="新建调拨订单.html",d="generationDate",e=new Date(1781593036009.74),f="defaultAdaptiveView",g="name",h="",i="size",j="width",k=0,l="height",m="adaptiveViews",n="sketchKeys",o="s0",p="variables",q="Variable_RKRW",r="NewVariable",s="page",t="packageId",u="3e7ec25c3a6b41bab32667bfbda47e0c",v="type",w="Axure:Page",x="新建调拨订单",y="notes",z="annotations",A="fn",B="1",C="ownerId",D="cc159ff30ccc47d79c887d8f9eb14459",E="label",F="合计金额：",G="说明",H="<p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">&nbsp;“合计金额”禁用，根据物料列表的价格自动计算，不要填写</span></p>",I="2",J="55fcc6dd584a4282bc7493a11e2e2c4a",K="调出属主：",L="<p><span>1.数据源：[ 属主 ]</span></p><p><span>2.默认值：根据数据源数量赋值</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a. [ 属主 ] 数据 = 1 ：默认对应的唯一属主</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b. [ 属主 ] 数据 ≥ 2 ：默认为空</span></p>",M="3",N="1c81b336e7c541b7985ca840a46a6038",O="调出仓库：",P="<p><span>数据源：仓库属性为“余料/物料/面料/辅料”的仓库</span></p>",Q="4",R="14257cbeabac470fbe39c3eb39a490bf",S="调入属主：",T="5",U="f876a2239ec84168abe138c4db66797e",V="调入仓库：",W="6",X="f5c3e34d9e914869ac9ff893ead792f1",Y=" 物料SKU编码",Z="<p><span style=\"font-family:'Arial Negreta', 'Arial Normal', 'Arial', sans-serif;font-weight:700;color:#333333;\">物料SKU编码</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">：</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">1. 数据源：采购订单内选择供应商对应的物料的sku。默认展示10条。向下滚动可加载新的数据。</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">2. SKU支持模糊搜索（物料名称、物料SKU）</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">3. 点击物料SKU，以字节阵形式展示 物料SKU编码 物料名称 规格 克重&nbsp; 颜色</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">4. 选中物料编码SKU，相应的物料名称、规格、克重自动带出</span></p>",ba="7",bb="42518cd8c5c841a492a26c543a5ebe2d",bc=" 物料编码",bd="<p><span style=\"font-family:'Arial Negreta', 'Arial Normal', 'Arial', sans-serif;font-weight:700;color:#333333;\">物料编码</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">：</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">1. 数据源：下拉选项较之前不做改变，仅展示顶部选中供应商下的物料</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">2. 选中物料后，</span><span style=\"font-family:'Arial Negreta', 'Arial Normal', 'Arial', sans-serif;font-weight:700;color:#333333;\">自动带出该物料的第一个供应商为对应选择的SKU信息</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">，含SKU编码 规格 克重&nbsp; 颜色</span></p>",be="8",bf="637ff820f48b4379ac2a7b636fab85da",bg="规格/门幅",bh="<p><span style=\"font-family:'Arial Negreta', 'Arial Normal', 'Arial', sans-serif;font-weight:700;color:#333333;\">规格/门幅</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">：</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">1. 数据源：数据源：物料明细中该物料已创建的规格。</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">2. 展示样式：“规格/门幅”(“克重”)</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">3. 变更规格后：“物料SKU编码”需按当前“物料-规格-颜色”查找一下是否存在对应SKU：</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">&nbsp;&nbsp; &nbsp; 3.1&nbsp; 若存在，将对应SKU调过去；</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">&nbsp;&nbsp; &nbsp; 3.2&nbsp; 若不存在，SKU字段展示为空。</span></p>",bi="9",bj="275a9c9243e9457f9add2e8daace4937",bk="颜色",bl="<p><span style=\"font-family:'Arial Negreta', 'Arial Normal', 'Arial', sans-serif;font-weight:700;color:#333333;\">颜色</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">：</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">1. 数据源：系统中所有颜色，可进行模糊搜索</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">2. “颜色”字体颜色区分标识： 若在物料明细中：蓝色 ； 颜色库中但非物料明细中：黑色</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">3. 变更颜色后：“物料SKU编码”需要按照当前“物料-规格-颜色”查找一下是否存在对应SKU：</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">&nbsp;&nbsp; &nbsp; 3.1&nbsp; 若存在，将对应SKU调过去；</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">&nbsp;&nbsp; &nbsp; 3.2&nbsp; 若不存在，SKU字段展示为空。</span></p>",bm="10",bn="ef3c2e8fcce7470a80385fb72621b0a8",bo="保存",bp="<p><span style=\"color:#333333;\">1.校验选择的 &quot;调出属主-调出仓库” 和 &quot;调入属主-调入仓库” 不能相同，否则Toast提示：调入与调出目的一致</span></p><p><span style=\"color:#333333;\">2.若“调拨类型”为</span><span style=\"color:#02A7F0;\">出入库调拨</span></p><p><span style=\"color:#333333;\">&nbsp;&nbsp; &nbsp; a.创建调拨单，调拨单状态置为“</span><span style=\"color:#D9001B;\">待开启</span><span style=\"color:#333333;\">”</span></p><p><span style=\"color:#333333;\">3.若“调拨类型”为</span><span style=\"color:#02A7F0;\">快速调拨</span></p><p><span style=\"color:#333333;\">&nbsp;&nbsp; &nbsp; a.校验SKU清单在‘调出部门-调出仓库’内无任何绑定（未被订单号/款号绑定）的未锁库存是否足够</span></p><p><span style=\"color:#333333;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp;&nbsp; i.库存不足：保存失败，提示“调出库存不足”</span></p><p><span style=\"color:#333333;\">&nbsp;&nbsp; &nbsp; b.通过校验</span></p><p><span style=\"color:#333333;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp;&nbsp; i.创建调拨单，调拨单状态置为“</span><span style=\"color:#D9001B;\">调拨完成</span><span style=\"color:#333333;\">”</span></p><p><span style=\"color:#333333;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp;&nbsp; ii.以按量拣货逻辑对SKU的批次码进行出库</span></p><p><span style=\"color:#333333;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; ①创建[出库单]</span></p><p><span style=\"color:#333333;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; 1.出库单编号规则：'CKD'+'6位年月日'+'2位流水'，例：CKD23073101</span></p><p><span style=\"color:#333333;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; 2.出库类型：调拨出库</span></p><p><span style=\"color:#333333;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; 3.关联业务：当前“调拨单号”</span></p><p><span style=\"color:#333333;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; 4.操作人、操作日期：取当前操作人和日期(年-月-日)</span></p><p><span style=\"color:#333333;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; 5.其它字段为空</span></p><p><span style=\"color:#333333;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; ②将批次码的出库情况记录至[出库单]详情中</span></p><p><span style=\"color:#333333;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; 1.记录字段：批次码、物料编码、物料名称、颜色、规格/门幅、数量、单位</span></p><p><span style=\"color:#333333;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; ③将批次码的出库情况记录至[出库明细]报表中</span></p><p><span style=\"color:#333333;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; ④将批次码的出库情况记录至[出入库明细]报表中</span></p><p><span style=\"color:#333333;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp;&nbsp; iii.将以上出库的批次码，入库至调拨单的‘调入属主-调入仓库’中</span></p><p><span style=\"color:#333333;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; ①创建[入库单]</span></p><p><span style=\"color:#333333;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; 1.入库单编号规则：'RKD'+'6位年月日'+'2位流水'，例：RKD23073101</span></p><p><span style=\"color:#333333;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; 2.入库类型：调拨入库</span></p><p><span style=\"color:#333333;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; 3.关联业务：当前“调拨单号”</span></p><p><span style=\"color:#333333;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; 4.操作人、操作日期：取当前操作人和日期(年-月-日)</span></p><p><span style=\"color:#333333;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; 5.其它字段为空</span></p><p><span style=\"color:#333333;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; ②将批次码的入库情况记录至[入库单]详情中</span></p><p><span style=\"color:#333333;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; 1.记录字段：批次码、物料编码、物料名称、颜色、规格/门幅、数量、单位</span></p><p><span style=\"color:#333333;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; ③将批次码的入库情况记录至[入库明细]报表中</span></p><p><span style=\"color:#333333;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; ④将批次码的入库情况记录至[出入库明细]报表中</span></p>",bq="style",br="baseStyle",bs="627587b6038d43cca051c114ac41ad32",bt="pageAlignment",bu="center",bv="fill",bw="fillType",bx="solid",by="color",bz=0xFFFFFFFF,bA="image",bB="imageAlignment",bC="near",bD="imageRepeat",bE="auto",bF="favicon",bG="sketchFactor",bH="0",bI="colorStyle",bJ="appliedColor",bK="fontName",bL="Applied Font",bM="borderWidth",bN="borderVisibility",bO="borderFill",bP=0xFF797979,bQ="cornerRadius",bR="cornerVisibility",bS="outerShadow",bT="on",bU=false,bV="offsetX",bW=5,bX="offsetY",bY="blurRadius",bZ="spread",ca="r",cb=0,cc="g",cd="b",ce="a",cf=0.349019607843137,cg="adaptiveStyles",ch="interactionMap",ci="diagram",cj="objects",ck="id",cl="f02a73abd3d14253bcb5b537f332b6a4",cm="friendlyType",cn="标题-1350",co="referenceDiagramObject",cp="styleType",cq="visible",cr=true,cs=1350,ct=120,cu="imageOverrides",cv="masterId",cw="55e23feaedaa46eaa84848efc29f0f2a",cx="be2ed751674d41a89044c70b872f56be",cy="母版",cz=10,cA="bdaeed3774644546913b266f76aa115f",cB="27d6d384bb49497695b15f82e8fd691b",cC="矩形",cD="vectorShape",cE="'微软雅黑', sans-serif",cF="foreGroundFill",cG=0xFF000000,cH="opacity",cI=1,cJ=60,cK=32,cL="5f44b79bbafd43f5b58194dfb3f6f145",cM=0xFF3399FF,cN="stateStyles",cO="mouseOver",cP=0xFF81D3F8,cQ="mouseDown",cR="disabled",cS=0xFFD3